"use client";

import { motion } from "framer-motion";
import { HuffmanNode } from "./HuffmanGame";

export default function NodeCard({ node, onDrop }: {
  node: HuffmanNode;
  onDrop: (e: any, source: HuffmanNode) => void;
}) {
  return (
    <motion.div
      drag
      dragMomentum={false}
      onDragEnd={(e) => onDrop(e, node)}
      data-node-id={node.id}
      whileHover={{ scale: 1.05 }}
      whileTap={{ scale: 0.95 }}
      className="p-4 rounded-2xl bg-white/10 backdrop-blur-xl border border-white/15 
                 text-center cursor-grab active:cursor-grabbing select-none shadow-lg"
    >
      <div className="text-lg font-semibold">{node.label}</div>
      <div className="text-sm text-white/70">{node.value}</div>
      {node.isLeaf && (
        <div className="mt-1 text-xs text-emerald-300/80">Symbole</div>
      )}
    </motion.div>
  );
}
