"use client";

import { motion } from "framer-motion";
import { HuffmanNode } from "./HuffmanGame";

export default function HuffmanTree({ root }: { root: HuffmanNode | null }) {
  if (!root)
    return <div className="text-white/50 text-sm">Complète l'arbre pour l'afficher.</div>;

  const renderNode = (node: HuffmanNode) => (
    <div className="flex flex-col items-center">
      <motion.div
        initial={{ opacity: 0, y: -10 }}
        animate={{ opacity: 1, y: 0 }}
        className={`px-3 py-2 rounded-xl border mb-2 shadow-md ${
          !node.left && !node.right
            ? "bg-emerald-500/20 border-emerald-300/50"
            : "bg-white/10 border-white/30"
        }`}
      >
        <div className="font-semibold">{node.label}</div>
        <div className="text-xs text-white/70">freq: {node.value}</div>
      </motion.div>

      {(node.left || node.right) && (
        <div className="flex items-start gap-6">
          {node.left && (
            <div className="flex flex-col items-center">
              <div className="text-xs text-white/50">0</div>
              {renderNode(node.left)}
            </div>
          )}
          {node.right && (
            <div className="flex flex-col items-center">
              <div className="text-xs text-white/50">1</div>
              {renderNode(node.right)}
            </div>
          )}
        </div>
      )}
    </div>
  );

  return <div className="max-h-[340px] overflow-auto">{renderNode(root)}</div>;
}
